class A:
    def x(self): print('A', end='')
class B(A):
    def x(self): print('B', end=''); super().x()
class C(A):
    def x(self): print('C', end='')
class D(B, C):
    def x(self): print('D', end=''); super().x()
D().x()

def multipliers():
    return [lambda x: i * x for i in range(4)]
print([m(2) for m in multipliers()])

for i in range(3):
    if i == 1: break
else:
    print('Done')

class Meta(type):
    def __call__(cls):
        print('M', end='')
        return super().__call__()
class MyClass(metaclass=Meta):
    def __init__(self): print('I', end='')
MyClass()

class A:
    __slots__ = ['a']
obj = A()
obj.a = 1
try:
    obj.b = 2
except AttributeError:
    print('Error')

class Descriptor:
    def __get__(self, obj, type): return 'D'
class A:
    x = Descriptor()
    def __init__(self): self.x = 'I'
print(A().x)

x = 5
def f():
    x += 1
try:
    f()
except UnboundLocalError:
    print('Error')

