class A { A() { System.out.print("A"); } }
class B extends A { B() { System.out.print("B"); } }
new B();

class Parent {
    static { System.out.print("1"); }
    { System.out.print("2"); }
    Parent() { System.out.print("3"); }
}
class Child extends Parent {
    static { System.out.print("4"); }
    { System.out.print("5"); }
    Child() { System.out.print("6"); }
}
new Child();

