class Node<T> {
    public void setData(T data) { System.out.print("N"); }
}
class MyNode extends Node<Integer> {
    public void setData(Integer data) { System.out.print("M"); }
}
Node n = new MyNode();
n.setData("hi");

Object o = new Object() {
    public boolean equals(Object obj) { return true; }
};
System.out.println(o.equals("hi"));

volatile int x = 0;
